    idle,
    one_a,
    circumflex,
    literal,
};

pub const ProcessKeyEventResult = extern struct {
    num_backspaces: u8,
    num_chars: u8,
    swallow_event: bool,
    chars: [*]const u16,
};

var state: State = .idle;
var first_a_upper: bool = false;
var gap: u8 = 0;

var bufs: [2][2]u16 = .{ .{ 0, 0 }, .{ 0, 0 } };
var active: u1 = 0;

const passthrough: ProcessKeyEventResult = .{
    .num_backspaces = 0,
    .num_chars = 0,
    .swallow_event = false,
    .chars = @ptrCast(&bufs[0]),
};

fn emit(num_backspaces: u8, chars: []const u16) ProcessKeyEventResult {
    const buf = @as([*]u16, @ptrCast(&bufs[active]));
    for (chars, 0..) |c, i| buf[i] = c;
    active ^= 1;
    return .{
        .num_backspaces = num_backspaces,
        .num_chars = @intCast(chars.len),
        .swallow_event = true,
        .chars = buf,
    };
}

fn isA(c: u16) bool {
    return c == 'a' or c == 'A';
}

fn isAlphanumeric(c: u16) bool {
    return (c >= '0' and c <= '9') or
        (c >= 'A' and c <= 'Z') or
        (c >= 'a' and c <= 'z');
}

