        reset_state();
        return passthrough;
    } else if (state == .idle) {
        return passthrough;
    }

    if (gap >= 255) {
        reset_state();
        return passthrough;
    }
    gap += 1;
    return passthrough;
}

fn handleA(char_code: u16) ProcessKeyEventResult {
    const upper = char_code == 'A';
    switch (state) {
        .idle => {
            state = .one_a;
            first_a_upper = upper;
            return passthrough;
        },
        .one_a => {
            state = .circumflex;
            const c: u16 = if (first_a_upper) 0x00C2 else 0x00E2;
            return emit(1, &.{c});
